---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  label?: string
  defaultValue?: string
  defaultSearch?: string
  shouldFilter?: boolean
  loop?: boolean
  disablePointerSelection?: boolean
  vimBindings?: boolean
}

const {
  class: className,
  label,
  defaultValue,
  defaultSearch,
  shouldFilter,
  loop,
  disablePointerSelection,
  vimBindings,
  ...props
} = Astro.props
---

<div
  data-slot="command"
  data-label={label}
  data-default-value={defaultValue}
  data-default-search={defaultSearch}
  data-should-filter={shouldFilter}
  data-loop={loop}
  data-disable-pointer-selection={disablePointerSelection}
  data-vim-bindings={vimBindings}
  class={cn(
    "bg-popover text-popover-foreground flex size-full flex-col overflow-hidden rounded-xl! p-1",
    className
  )}
  {...props}
>
  <slot />
</div>

<script>
  import { create } from "@data-slot/command"

  const initCommand = () => {
    create()

    document.querySelectorAll("[data-slot=command]").forEach((command) => {
      if (!(command instanceof HTMLElement)) return
      if (command.dataset.linkNavigation === "true") return

      command.dataset.linkNavigation = "true"
      command.addEventListener("command:select", (event) => {
        const { detail } = event as CustomEvent<{ value?: unknown }>
        const value = detail?.value
        if (typeof value !== "string") return

        const item = Array.from(
          command.querySelectorAll("[data-slot=command-item][href]")
        ).find((item) => item.getAttribute("data-value") === value)
        const href = item?.getAttribute("href")

        if (href) window.location.href = href
      })
    })
  }

  initCommand()

  document.addEventListener("astro:page-load", initCommand)
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  heading?: string
  value?: string
  forceMount?: boolean
}

const { class: className, heading, value, forceMount, ...props } = Astro.props
---

<div
  data-slot="command-group"
  data-value={value}
  data-force-mount={forceMount ? "true" : undefined}
  class={cn(
    "text-foreground [&_[data-slot=command-group-heading]]:text-muted-foreground overflow-hidden p-1 [&_[data-slot=command-group-heading]]:px-2 [&_[data-slot=command-group-heading]]:py-1.5 [&_[data-slot=command-group-heading]]:text-xs [&_[data-slot=command-group-heading]]:font-medium",
    className
  )}
  {...props}
>
  {heading && <div data-slot="command-group-heading">{heading}</div>}
  <slot />
</div>

---
import CheckIcon from "@lucide/astro/icons/check"
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"a"> & {
  disabled?: boolean
  href?: string
  value?: string
  label?: string
  keywords?: string | string[]
  forceMount?: boolean
}

const {
  class: className,
  disabled,
  href,
  value,
  label,
  keywords,
  forceMount,
  ...props
} = Astro.props

const Tag = href ? "a" : "div"
const keywordsValue = Array.isArray(keywords) ? keywords.join(", ") : keywords
---

<Tag
  data-slot="command-item"
  data-disabled={disabled ? "true" : undefined}
  data-value={value}
  data-label={label}
  data-keywords={keywordsValue}
  data-force-mount={forceMount ? "true" : undefined}
  href={href}
  class={cn(
    "group/command-item data-selected:bg-accent data-selected:text-accent-foreground data-selected:**:[svg]:text-accent-foreground href:cursor-pointer href:no-underline relative flex cursor-default items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-hidden select-none in-data-[slot=dialog-content]:rounded-lg! data-[disabled=true]:pointer-events-none data-[disabled=true]:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
    className
  )}
  {...props}
>
  <slot />
  <CheckIcon
    class="ml-auto opacity-0 group-has-data-[slot=command-shortcut]/command-item:hidden group-data-[checked=true]/command-item:opacity-100"
  />
</Tag>
